import{_ as n,c as i,o as t,a1 as a}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Schnellstart: In 5 Minuten loslegen | Plannotator","description":"Lernen Sie die Installation und Konfiguration von Plannotator. Installieren Sie die CLI in 5 Minuten, konfigurieren Sie das Claude Code- oder OpenCode-Plugin und beherrschen Sie den Plan-Review- und Code-Review-Workflow.","frontmatter":{"title":"Schnellstart: In 5 Minuten loslegen | Plannotator","sidebarTitle":"In 5 Minuten loslegen","subtitle":"Schnellstart: In 5 Minuten mit Plannotator loslegen","description":"Lernen Sie die Installation und Konfiguration von Plannotator. Installieren Sie die CLI in 5 Minuten, konfigurieren Sie das Claude Code- oder OpenCode-Plugin und beherrschen Sie den Plan-Review- und Code-Review-Workflow.","tags":["Schnellstart","Einstieg","Installation","Claude Code","OpenCode"],"order":1},"headers":[],"relativePath":"de/backnotprop/plannotator/start/getting-started/index.md","filePath":"de/backnotprop/plannotator/start/getting-started/index.md"}'),s={name:"de/backnotprop/plannotator/start/getting-started/index.md"};function l(r,e,o,d,p,h){return t(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="schnellstart-in-5-minuten-mit-plannotator-loslegen" tabindex="-1">Schnellstart: In 5 Minuten mit Plannotator loslegen <a class="header-anchor" href="#schnellstart-in-5-minuten-mit-plannotator-loslegen" aria-label="Permalink to &quot;Schnellstart: In 5 Minuten mit Plannotator loslegen&quot;">​</a></h1><h2 id="was-sie-nach-dieser-lektion-konnen" tabindex="-1">Was Sie nach dieser Lektion können <a class="header-anchor" href="#was-sie-nach-dieser-lektion-konnen" aria-label="Permalink to &quot;Was Sie nach dieser Lektion können&quot;">​</a></h2><ul><li>✅ Die Kernfunktionen und Anwendungsfälle von Plannotator verstehen</li><li>✅ Plannotator in 5 Minuten installieren</li><li>✅ Claude Code oder OpenCode Integration konfigurieren</li><li>✅ Ihren ersten Plan-Review und Code-Review durchführen</li></ul><h2 id="ihr-aktuelles-problem" tabindex="-1">Ihr aktuelles Problem <a class="header-anchor" href="#ihr-aktuelles-problem" aria-label="Permalink to &quot;Ihr aktuelles Problem&quot;">​</a></h2><p><strong>Plannotator</strong> ist ein interaktives Review-Tool für Claude Code und OpenCode, das folgende Probleme löst:</p><p><strong>Problem 1</strong>: Von AI generierte Implementierungspläne im Terminal zu lesen ist mühsam – zu viel Text, unklare Struktur, anstrengende Reviews.</p><p><strong>Problem 2</strong>: Feedback an die AI zu geben erfordert umständliche Textbeschreibungen wie &quot;lösche Absatz 3&quot; oder &quot;ändere diese Funktion&quot; – hoher Kommunikationsaufwand.</p><p><strong>Problem 3</strong>: Beim Code-Review müssen mehrere Terminals oder IDEs geöffnet werden, ständiges Wechseln erschwert die Konzentration.</p><p><strong>Problem 4</strong>: Teammitglieder möchten am Review teilnehmen, wissen aber nicht, wie sie Planinhalte teilen können.</p><p><strong>Plannotator hilft Ihnen</strong>:</p><ul><li>Visuelle Benutzeroberfläche statt Terminal-Lesen, klare Struktur</li><li>Text markieren und Anmerkungen hinzufügen (Löschen, Ersetzen, Kommentieren), präzises Feedback</li><li>Git-Diff visuell reviewen, Anmerkungen auf Zeilenebene</li><li>URL-Sharing-Funktion, Teamzusammenarbeit ohne Backend</li></ul><h2 id="wann-diese-methode-verwenden" tabindex="-1">Wann diese Methode verwenden <a class="header-anchor" href="#wann-diese-methode-verwenden" aria-label="Permalink to &quot;Wann diese Methode verwenden&quot;">​</a></h2><p><strong>Geeignete Szenarien</strong>:</p><ul><li>Sie verwenden Claude Code oder OpenCode für AI-gestützte Entwicklung</li><li>Sie müssen von AI generierte Implementierungspläne reviewen</li><li>Sie müssen Codeänderungen überprüfen</li><li>Sie müssen Plan- oder Code-Review-Ergebnisse mit Teammitgliedern teilen</li></ul><p><strong>Nicht geeignete Szenarien</strong>:</p><ul><li>Rein manuelles Programmieren (keine AI-generierten Pläne)</li><li>Sie haben bereits einen vollständigen Code-Review-Prozess (z.B. GitHub PR)</li><li>Sie benötigen kein visuelles Review-Tool</li></ul><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><h3 id="was-ist-plannotator" tabindex="-1">Was ist Plannotator <a class="header-anchor" href="#was-ist-plannotator" aria-label="Permalink to &quot;Was ist Plannotator&quot;">​</a></h3><p><strong>Plannotator</strong> ist ein interaktives Review-Tool für AI Coding Agents (Claude Code, OpenCode) mit zwei Hauptfunktionen:</p><ol><li><strong>Plan-Review</strong>: Visuelles Review von AI-generierten Implementierungsplänen mit Anmerkungen, Genehmigung oder Ablehnung</li><li><strong>Code-Review</strong>: Visuelles Review von Git-Diffs mit Anmerkungen auf Zeilenebene und verschiedenen Ansichtsmodi</li></ol><h3 id="funktionsweise" tabindex="-1">Funktionsweise <a class="header-anchor" href="#funktionsweise" aria-label="Permalink to &quot;Funktionsweise&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (Plan erstellen)│</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Plannotator   │  ← Lokaler HTTP-Server</span></span>
<span class="line"><span>│  (Visuelle UI) │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Browser       │</span></span>
<span class="line"><span>│  (Benutzer-Review)│</span></span>
<span class="line"><span>└─────────────────┘</span></span></code></pre></div><p><strong>Kernablauf</strong>:</p><ol><li>AI Agent erstellt Plan oder Codeänderungen</li><li>Plannotator startet lokalen HTTP-Server und öffnet Browser</li><li>Benutzer sieht Plan/Code im Browser und fügt Anmerkungen hinzu</li><li>Benutzer genehmigt oder lehnt ab, Plannotator gibt Entscheidung an AI Agent zurück</li><li>AI Agent setzt Implementierung fort oder nimmt Änderungen vor</li></ol><h3 id="sicherheit" tabindex="-1">Sicherheit <a class="header-anchor" href="#sicherheit" aria-label="Permalink to &quot;Sicherheit&quot;">​</a></h3><p><strong>Alle Daten werden lokal verarbeitet</strong>, nichts wird in die Cloud hochgeladen:</p><ul><li>Planinhalte, Code-Diffs und Anmerkungen werden auf Ihrem lokalen Rechner gespeichert</li><li>Lokaler HTTP-Server verwendet zufälligen Port (oder festen Port)</li><li>URL-Sharing komprimiert Daten in den URL-Hash, kein Backend erforderlich</li></ul><h2 id="🎒-vorbereitungen" tabindex="-1">🎒 Vorbereitungen <a class="header-anchor" href="#🎒-vorbereitungen" aria-label="Permalink to &quot;🎒 Vorbereitungen&quot;">​</a></h2><p><strong>Systemanforderungen</strong>:</p><ul><li>Betriebssystem: macOS / Linux / Windows / WSL</li><li>Laufzeit: Bun (wird vom Installationsskript automatisch behandelt)</li><li>AI-Umgebung: Claude Code 2.1.7+ oder OpenCode</li></ul><p><strong>Installationsoptionen</strong>:</p><ul><li>Bei Verwendung von Claude Code: CLI + Plugin installieren</li><li>Bei Verwendung von OpenCode: Plugin konfigurieren</li><li>Nur für Code-Review: Nur CLI installieren</li></ul><h2 id="folgen-sie-mir" tabindex="-1">Folgen Sie mir <a class="header-anchor" href="#folgen-sie-mir" aria-label="Permalink to &quot;Folgen Sie mir&quot;">​</a></h2><h3 id="schritt-1-plannotator-cli-installieren" tabindex="-1">Schritt 1: Plannotator CLI installieren <a class="header-anchor" href="#schritt-1-plannotator-cli-installieren" aria-label="Permalink to &quot;Schritt 1: Plannotator CLI installieren&quot;">​</a></h3><p><strong>macOS / Linux / WSL</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://plannotator.ai/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p><strong>Windows PowerShell</strong>:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">irm https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">plannotator.ai</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">install.ps1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> iex</span></span></code></pre></div><p><strong>Windows CMD</strong>:</p><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fsSL https://plannotator.ai/install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">o install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> del install.cmd</span></span></code></pre></div><p><strong>Sie sollten sehen</strong>: Das Installationsskript lädt die Plannotator CLI herunter, fügt sie zum Systempfad hinzu und zeigt die Versionsnummer an (z.B. &quot;plannotator v0.6.7 installed to ...&quot;).</p><div class="tip custom-block"><p class="custom-block-title">Was macht das Installationsskript?</p><p>Das Installationsskript:</p><ol><li>Lädt die neueste Version der Plannotator CLI herunter</li><li>Fügt sie zum Systempfad (PATH) hinzu</li><li>Bereinigt möglicherweise vorhandene alte Versionen</li><li>Installiert automatisch den <code>/plannotator-review</code> Befehl (für Code-Review)</li></ol></div><h3 id="schritt-2-claude-code-konfigurieren-optional" tabindex="-1">Schritt 2: Claude Code konfigurieren (optional) <a class="header-anchor" href="#schritt-2-claude-code-konfigurieren-optional" aria-label="Permalink to &quot;Schritt 2: Claude Code konfigurieren (optional)&quot;">​</a></h3><p>Wenn Sie Claude Code verwenden, müssen Sie das Plugin installieren.</p><p><strong>In Claude Code ausführen</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin marketplace add backnotprop/plannotator</span></span>
<span class="line"><span>/plugin install plannotator@plannotator</span></span></code></pre></div><p><strong>Wichtig</strong>: Nach der Plugin-Installation <strong>muss Claude Code neu gestartet werden</strong>, damit die Hooks wirksam werden.</p><p><strong>Sie sollten sehen</strong>: Nach erfolgreicher Plugin-Installation erscheint <code>plannotator</code> in der Plugin-Liste von Claude Code.</p><div class="info custom-block"><p class="custom-block-title">Manuelle Konfiguration (optional)</p><p>Wenn Sie das Plugin-System nicht verwenden möchten, können Sie den Hook manuell konfigurieren. Siehe Kapitel <a href="./../installation-claude-code/">Claude Code Plugin-Installation</a>.</p></div><h3 id="schritt-3-opencode-konfigurieren-optional" tabindex="-1">Schritt 3: OpenCode konfigurieren (optional) <a class="header-anchor" href="#schritt-3-opencode-konfigurieren-optional" aria-label="Permalink to &quot;Schritt 3: OpenCode konfigurieren (optional)&quot;">​</a></h3><p>Wenn Sie OpenCode verwenden, müssen Sie die Datei <code>opencode.json</code> bearbeiten.</p><p><strong><code>opencode.json</code> bearbeiten</strong>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;$schema&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://opencode.ai/config.json&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@plannotator/opencode@latest&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>OpenCode neu starten</strong>.</p><p><strong>Sie sollten sehen</strong>: Nach dem Neustart lädt OpenCode das Plugin automatisch und das <code>submit_plan</code> Tool wird verfügbar.</p><h3 id="schritt-4-erster-plan-review-claude-code-beispiel" tabindex="-1">Schritt 4: Erster Plan-Review (Claude Code Beispiel) <a class="header-anchor" href="#schritt-4-erster-plan-review-claude-code-beispiel" aria-label="Permalink to &quot;Schritt 4: Erster Plan-Review (Claude Code Beispiel)&quot;">​</a></h3><p><strong>Auslösebedingung</strong>: Lassen Sie Claude Code einen Implementierungsplan erstellen und <code>ExitPlanMode</code> aufrufen.</p><p><strong>Beispieldialog</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Benutzer: Erstelle mir einen Implementierungsplan für ein Benutzerauthentifizierungsmodul</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude: Okay, hier ist der Implementierungsplan:</span></span>
<span class="line"><span>1. Benutzermodell erstellen</span></span>
<span class="line"><span>2. Registrierungs-API implementieren</span></span>
<span class="line"><span>3. Login-API implementieren</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>(ruft ExitPlanMode auf)</span></span></code></pre></div><p><strong>Sie sollten sehen</strong>:</p><ol><li>Browser öffnet automatisch die Plannotator UI</li><li>Zeigt den von AI generierten Planinhalt</li><li>Sie können Plantext markieren und Anmerkungen hinzufügen (Löschen, Ersetzen, Kommentieren)</li><li>Unten befinden sich &quot;Approve&quot; und &quot;Request Changes&quot; Buttons</li></ol><p><strong>Aktionen</strong>:</p><ol><li>Plan im Browser ansehen</li><li>Wenn der Plan in Ordnung ist, klicken Sie <strong>Approve</strong> → AI setzt Implementierung fort</li><li>Wenn Änderungen nötig sind, markieren Sie den zu ändernden Text, klicken Sie <strong>Delete</strong>, <strong>Replace</strong> oder <strong>Comment</strong> → klicken Sie <strong>Request Changes</strong></li></ol><p><strong>Sie sollten sehen</strong>: Nach dem Klick schließt sich der Browser automatisch und Claude Code erhält Ihre Entscheidung und fährt mit der Ausführung fort.</p><h3 id="schritt-5-erster-code-review" tabindex="-1">Schritt 5: Erster Code-Review <a class="header-anchor" href="#schritt-5-erster-code-review" aria-label="Permalink to &quot;Schritt 5: Erster Code-Review&quot;">​</a></h3><p><strong>Im Projektverzeichnis ausführen</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>Sie sollten sehen</strong>:</p><ol><li>Browser öffnet die Code-Review-Seite</li><li>Zeigt Git-Diff (standardmäßig nicht committete Änderungen)</li><li>Links der Dateibaum, rechts der Diff-Viewer</li><li>Klicken Sie auf Zeilennummern, um Codebereiche auszuwählen und Anmerkungen hinzuzufügen</li></ol><p><strong>Aktionen</strong>:</p><ol><li>Codeänderungen im Diff-Viewer durchsehen</li><li>Auf Zeilennummern klicken, um zu reviewenden Code auszuwählen</li><li>Im rechten Panel Anmerkungen hinzufügen (comment/suggestion/concern)</li><li>Klicken Sie <strong>Send Feedback</strong> um an den Agent zu senden, oder <strong>LGTM</strong> zum Genehmigen</li></ol><p><strong>Sie sollten sehen</strong>: Nach Klick auf Send Feedback schließt sich der Browser, das Terminal gibt formatiertes Feedback aus und der Agent verarbeitet es automatisch.</p><h2 id="kontrollpunkt-✅" tabindex="-1">Kontrollpunkt ✅ <a class="header-anchor" href="#kontrollpunkt-✅" aria-label="Permalink to &quot;Kontrollpunkt ✅&quot;">​</a></h2><p>Nach Abschluss der obigen Schritte sollten Sie:</p><ul><li>[ ] Installationsskript zeigt &quot;plannotator vX.X.X installed to ...&quot;</li><li>[ ] In Claude Code Plan-Review auslösen, Browser öffnet automatisch UI</li><li>[ ] In der UI Plantext markieren und Anmerkungen hinzufügen</li><li>[ ] Approve oder Request Changes klicken, Browser schließt sich</li><li>[ ] <code>/plannotator-review</code> ausführen, Code-Review-Oberfläche sehen</li><li>[ ] Im Code-Review Anmerkungen auf Zeilenebene hinzufügen, Send Feedback klicken</li></ul><p><strong>Bei Fehlern in einem Schritt</strong>, siehe:</p><ul><li><a href="./../installation-claude-code/">Claude Code Installationsanleitung</a></li><li><a href="./../installation-opencode/">OpenCode Installationsanleitung</a></li><li><a href="./../../faq/common-problems/">Häufige Probleme</a></li></ul><h2 id="haufige-fehler" tabindex="-1">Häufige Fehler <a class="header-anchor" href="#haufige-fehler" aria-label="Permalink to &quot;Häufige Fehler&quot;">​</a></h2><p><strong>Fehler 1</strong>: Nach Installation zeigt <code>plannotator</code> &quot;command not found&quot;</p><p><strong>Ursache</strong>: PATH-Umgebungsvariable nicht aktualisiert oder Terminal muss neu gestartet werden.</p><p><strong>Lösung</strong>:</p><ul><li>macOS/Linux: Führen Sie <code>source ~/.zshrc</code> oder <code>source ~/.bashrc</code> aus, oder starten Sie das Terminal neu</li><li>Windows: Starten Sie PowerShell oder CMD neu</li></ul><p><strong>Fehler 2</strong>: Nach Plugin-Installation in Claude Code wird Plan-Review nicht ausgelöst</p><p><strong>Ursache</strong>: Claude Code wurde nicht neu gestartet, Hooks sind nicht aktiv.</p><p><strong>Lösung</strong>: Beenden Sie Claude Code vollständig (nicht nur Fenster schließen) und öffnen Sie es erneut.</p><p><strong>Fehler 3</strong>: Browser öffnet sich nicht automatisch</p><p><strong>Ursache</strong>: Möglicherweise Remote-Modus (z.B. Devcontainer, SSH) oder Port ist belegt.</p><p><strong>Lösung</strong>:</p><ul><li>Prüfen Sie, ob die Umgebungsvariable <code>PLANNOTATOR_REMOTE=1</code> gesetzt ist</li><li>Sehen Sie die URL in der Terminal-Ausgabe und öffnen Sie sie manuell im Browser</li><li>Siehe <a href="./../../advanced/remote-mode/">Remote-/Devcontainer-Modus</a></li></ul><p><strong>Fehler 4</strong>: Code-Review zeigt &quot;No changes&quot;</p><p><strong>Ursache</strong>: Aktuell keine nicht committeten Git-Änderungen.</p><p><strong>Lösung</strong>:</p><ul><li>Führen Sie zuerst <code>git status</code> aus, um Änderungen zu bestätigen</li><li>Oder führen Sie <code>git add</code> aus, um einige Dateien zu stagen</li><li>Oder wechseln Sie zu einem anderen Diff-Typ (z.B. last commit)</li></ul><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><p>Plannotator ist ein lokal laufendes Review-Tool, das durch visuelle UI die Effizienz von Plan-Review und Code-Review steigert:</p><p><strong>Kernfunktionen</strong>:</p><ul><li><strong>Plan-Review</strong>: Visuelles Review von AI-generierten Plänen mit präzisen Anmerkungen</li><li><strong>Code-Review</strong>: Visuelles Review von Git-Diffs mit Anmerkungen auf Zeilenebene</li><li><strong>URL-Sharing</strong>: Review-Inhalte ohne Backend teilen</li><li><strong>Drittanbieter-Integration</strong>: Genehmigte Pläne automatisch in Obsidian/Bear speichern</li></ul><p><strong>Kernvorteile</strong>:</p><ul><li>Lokale Ausführung, Datensicherheit</li><li>Visuelle UI, höhere Effizienz</li><li>Präzises Feedback, geringerer Kommunikationsaufwand</li><li>Teamzusammenarbeit ohne Kontosystem</li></ul><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../installation-claude-code/">Claude Code Plugin-Installation</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Detaillierte Schritte zur Claude Code Plugin-Installation</li><li>Methode zur manuellen Hook-Konfiguration</li><li>Wie Sie überprüfen, ob die Installation erfolgreich war</li><li>Lösungen für häufige Installationsprobleme</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie hier, um die Quellcode-Position anzuzeigen</strong></summary><blockquote><p>Aktualisierungsdatum: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>CLI-Einstieg (Plan-Review)</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L1-L50" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></td><td>1-50</td></tr><tr><td>CLI-Einstieg (Code-Review)</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L46-L84" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></td><td>46-84</td></tr><tr><td>Plan-Review-Server</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L1-L200" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>1-200</td></tr><tr><td>Code-Review-Server</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/review.ts#L1-L150" target="_blank" rel="noreferrer"><code>packages/server/review.ts</code></a></td><td>1-150</td></tr><tr><td>Git-Tools</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L1-L100" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>1-100</td></tr><tr><td>Plan-Review-UI</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>1-200</td></tr><tr><td>Code-Review-UI</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></td><td>1-200</td></tr></tbody></table><p><strong>Wichtige Konstanten</strong>:</p><ul><li><code>MAX_RETRIES = 5</code>: Anzahl der Port-Wiederholungsversuche (<code>packages/server/index.ts:80</code>)</li><li><code>RETRY_DELAY_MS = 500</code>: Verzögerung bei Port-Wiederholung (<code>packages/server/index.ts:80</code>)</li></ul><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>startPlannotatorServer()</code>: Startet den Plan-Review-Server (<code>packages/server/index.ts</code>)</li><li><code>startReviewServer()</code>: Startet den Code-Review-Server (<code>packages/server/review.ts</code>)</li><li><code>runGitDiff()</code>: Führt git diff Befehl aus (<code>packages/server/git.ts</code>)</li></ul><p><strong>Umgebungsvariablen</strong>:</p><ul><li><code>PLANNOTATOR_REMOTE</code>: Remote-Modus-Flag (<code>apps/hook/server/index.ts:17</code>)</li><li><code>PLANNOTATOR_PORT</code>: Fester Port (<code>apps/hook/server/index.ts:18</code>)</li><li><code>PLANNOTATOR_BROWSER</code>: Benutzerdefinierter Browser (<code>apps/hook/README.md:79</code>)</li><li><code>PLANNOTATOR_SHARE</code>: URL-Sharing-Schalter (<code>apps/hook/server/index.ts:44</code>)</li></ul></details>`,104)])])}const g=n(s,[["render",l]]);export{c as __pageData,g as default};
